const LICENSE_SECRET = "SVP_2026_9f7c2e51b4d84f38a1e9c7b6d5e4f301_ULTRA_LONG_SECRET";
function signPayload(payload) {
    return crypto.createHmac("sha256", LICENSE_SECRET).update(payload, "utf8").digest("hex");
}
function safeEqual(a, b) {
    const aa = Buffer.from(String(a || ""), "utf8");
    const bb = Buffer.from(String(b || ""), "utf8");
    if (aa.length !== bb.length) return false;
    return crypto.timingSafeEqual(aa, bb);
}
const premiumKey = normStr(global.get("premium.key"));
